import { useState } from "react";
import { type QuestionAnswers, type DiagnosticResult } from "@shared/schema";
import { REPORT_PAYLOAD_VERSION, encodeReportPayload } from "@shared/report-payload";
import { calculateExposureScore } from "@/lib/scoring";
import { useParentCommunication } from "@/hooks/useParentCommunication";
import { QuestionFlowScreen } from "@/components/QuestionFlow";
import { Loader2 } from "lucide-react";

type DiagnosticStep = "questions" | "submitting";

export default function Diagnostic() {
  const { notifyComplete } = useParentCommunication();
  const [step, setStep] = useState<DiagnosticStep>("questions");

  const handleQuestionsComplete = (answers: QuestionAnswers) => {
    const scores = calculateExposureScore(answers);
    const submittedAt = new Date().toISOString();

    const diagnosticResult: DiagnosticResult = {
      ...scores,
      answers
    };

    setStep("submitting");

    const reportPayload = {
      v: REPORT_PAYLOAD_VERSION,
      s: diagnosticResult.exposureScore,
      b: diagnosticResult.exposureBand,
      p: diagnosticResult.primaryDriver,
      t: diagnosticResult.anchorTimingBucket,
      d: diagnosticResult.dependencyFlag ? 1 : 0,
      a: answers,
      ts: submittedAt
    } as const;

    const reportBaseUrl = new URLSearchParams(window.location.search).get("reportBaseUrl");
    if (!reportBaseUrl) {
      return;
    }

    const reportDestinationUrl = new URL(reportBaseUrl, window.location.origin);
    reportDestinationUrl.searchParams.set("payload", encodeReportPayload(reportPayload));

    // Duplicate key fields as first-class query params for downstream tools (e.g. Marketo capture).
    reportDestinationUrl.searchParams.set("score", String(diagnosticResult.exposureScore));
    reportDestinationUrl.searchParams.set("band", diagnosticResult.exposureBand);
    reportDestinationUrl.searchParams.set("driver", diagnosticResult.primaryDriver);
    reportDestinationUrl.searchParams.set("timing", diagnosticResult.anchorTimingBucket);
    reportDestinationUrl.searchParams.set("dependency", diagnosticResult.dependencyFlag ? "1" : "0");
    reportDestinationUrl.searchParams.set("submittedAt", submittedAt);

    const reportDestination = reportDestinationUrl.toString();

    notifyComplete({
      payload: reportPayload,
      redirectUrl: reportDestination
    });
  };

  switch (step) {
    case "questions":
      return <QuestionFlowScreen onComplete={handleQuestionsComplete} />;
    case "submitting":
      return (
        <div className="min-h-screen app-gradient-bg flex items-center justify-center px-4">
          <div className="text-center">
            <Loader2 className="w-8 h-8 animate-spin text-primary mx-auto mb-4" />
            <p className="text-muted-foreground" data-testid="text-loading">
              Preparing your report...
            </p>
          </div>
        </div>
      );
    default:
      return null;
  }
}
