import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { ResultsScreen } from "@/components/Results";
import { parseReportPayloadFromLocation } from "@/lib/reportPayload";

export default function PdfDownloadPage() {
  try {
    const payload = parseReportPayloadFromLocation(window.location.search);

    return (
      <ResultsScreen
        exposureBand={payload.b}
        exposureScore={payload.s}
        primaryDriver={payload.p}
        dependencyFlag={payload.d === 1}
        anchorTimingBucket={payload.t}
        answers={payload.a}
      />
    );
  } catch (error) {
    return (
      <div className="min-h-screen app-gradient-bg flex items-center justify-center px-4">
        <Card className="w-full max-w-md border-card-border">
          <CardContent className="pt-6 text-center">
            <p className="text-foreground mb-2" data-testid="text-invalid-payload-title">
              Invalid report link
            </p>
            <p className="text-muted-foreground text-sm mb-5" data-testid="text-invalid-payload-body">
              This report link is missing data or has expired.
            </p>
            <Button
              data-testid="button-start-over"
              onClick={() => {
                const url = new URL(window.location.href);
                url.searchParams.delete("payload");
                window.location.href = url.toString();
              }}
            >
              Start assessment again
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }
}
